// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract AgeVerifier {
    uint256 public minimumAge;

    constructor(uint256 _minimumAge) {
        require([[SLOT init_pos]], "Invalid minimum");
        minimumAge = _minimumAge;
    }

    function checkAge(uint256 age) external view returns (bool) {
        require([[SLOT age_check]], [[SLOT young_msg]]);
        return true;
    }

    function setMinimumAge(uint256 newMin) external {
        require(newMin > 0, "Invalid minimum");
        minimumAge = newMin;
    }
}
